package com.oneil.wellness.walkplanner.goal;import jakarta.persistence.*;import java.time.*;@Entity@Table(name="wellness_goal_settings")public class WellnessGoal{@Id private short id=1;private boolean enabled;@Column(name="weekly_minutes_target")private Integer weeklyMinutesTarget;@Column(name="weekly_walk_count_target")private Integer weeklyWalkCountTarget;@Column(name="minimum_qualifying_minutes")private Integer minimumQualifyingMinutes;@Enumerated(EnumType.STRING)@Column(name="week_starts_on",nullable=false)private DayOfWeek weekStartsOn;@Column(nullable=false)private String timezone;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected WellnessGoal(){}public WellnessGoal(WellnessGoalRequest r){update(r);}public void update(WellnessGoalRequest r){enabled=r.enabled();weeklyMinutesTarget=r.weeklyMinutesTarget();weeklyWalkCountTarget=r.weeklyWalkCountTarget();minimumQualifyingMinutes=r.minimumQualifyingMinutes();weekStartsOn=r.weekStartsOn()==null?DayOfWeek.MONDAY:r.weekStartsOn();timezone=r.timezone()==null||r.timezone().isBlank()?"UTC":ZoneId.of(r.timezone()).getId();updatedAt=Instant.now();}public boolean isEnabled(){return enabled;}public Integer getWeeklyMinutesTarget(){return weeklyMinutesTarget;}public Integer getWeeklyWalkCountTarget(){return weeklyWalkCountTarget;}public Integer getMinimumQualifyingMinutes(){return minimumQualifyingMinutes;}public DayOfWeek getWeekStartsOn(){return weekStartsOn;}public String getTimezone(){return timezone;}}
